import json

business_json_path = var_call_N94ru3q49vNlNGVGDk6HpjJI
with open(business_json_path, 'r', encoding='utf-8') as f:
    businesses = json.load(f)

review_aggs = var_call_Hvb2PFHhYRgwNmsOcjFPRsPG

US_STATES = set(['AL','AK','AZ','AR','CA','CO','CT','DE','FL','GA','HI','ID','IL','IN','IA','KS','KY','LA','ME','MD','MA','MI','MN','MS','MO','MT','NE','NV','NH','NJ','NM','NY','NC','ND','OH','OK','OR','PA','RI','SC','SD','TN','TX','UT','VT','VA','WA','WV','WI','WY','DC'])

# helper functions
def normalize_wifi_raw(v):
    if v is None:
        return None
    s = str(v).strip()
    if s.startswith("u'") or s.startswith('u"'):
        s = s[2:]
    if (s.startswith("'") and s.endswith("'")) or (s.startswith('"') and s.endswith('"')):
        s = s[1:-1]
    return s.strip().lower()

def extract_state_from_description(desc):
    if not isinstance(desc, str):
        return None
    parts = [p.strip() for p in desc.split(',') if p.strip()]
    # check last two parts for a 2-letter state code
    for part in parts[-3:]:
        if len(part) == 2 and part.isalpha() and part.upper() in US_STATES:
            return part.upper()
    # otherwise, check tokens
    for part in parts:
        tokens = part.split()
        for t in tokens:
            tt = t.strip().upper().strip('.')
            if len(tt) == 2 and tt.isalpha() and tt in US_STATES:
                return tt
    return None

# iterate businesses
state_wifi_counts = {}
state_business_ids = {}
for b in businesses:
    biz_id = b.get('business_id')
    attrs = b.get('attributes')
    wifi_raw = None
    if isinstance(attrs, dict):
        wifi_raw = attrs.get('WiFi')
    elif isinstance(attrs, str):
        # try to find pattern like "WiFi': 'free'" in string
        if 'WiFi' in attrs:
            # naive parse: find WiFi and following token
            idx = attrs.find('WiFi')
            rest = attrs[idx:]
            # split on colon or comma
            for sep in [":", "=", "'", '"']:
                if sep in rest:
                    parts = rest.split(sep)
                    if len(parts) > 1:
                        wifi_raw = parts[1].strip().split()[0]
                        break
    wifi_norm = normalize_wifi_raw(wifi_raw)
    wifi_offered = False
    if wifi_norm not in (None, '', 'no', 'none'):
        wifi_offered = True
    if not wifi_offered:
        continue
    desc = b.get('description')
    state = extract_state_from_description(desc)
    if state is None:
        continue
    state_wifi_counts[state] = state_wifi_counts.get(state, 0) + 1
    state_business_ids.setdefault(state, []).append(biz_id)

# determine max state
if not state_wifi_counts:
    result = {"state": None, "wifi_business_count": 0, "average_rating": None}
else:
    max_state = max(state_wifi_counts.items(), key=lambda x: x[1])[0]
    max_count = state_wifi_counts[max_state]
    biz_ids = state_business_ids.get(max_state, [])
    # convert to review refs
    biz_refs = [bid.replace('businessid_','businessref_') for bid in biz_ids]
    # aggregate reviews
    rdf = review_aggs
    # build mapping from business_ref to avg_rating and review_count
    ref_map = {}
    for r in rdf:
        ref = r.get('business_ref')
        try:
            avg = float(r.get('avg_rating')) if r.get('avg_rating') is not None else None
        except:
            avg = None
        try:
            cnt = int(r.get('review_count')) if r.get('review_count') is not None else 0
        except:
            cnt = 0
        ref_map[ref] = (avg, cnt)
    # compute weighted average across matched refs
    total_reviews = 0
    weighted_sum = 0.0
    matched_any = False
    for ref in biz_refs:
        if ref in ref_map:
            avg, cnt = ref_map[ref]
            if avg is not None and cnt is not None:
                matched_any = True
                total_reviews += cnt
                weighted_sum += avg * cnt
    if matched_any and total_reviews>0:
        average_rating = round(weighted_sum/total_reviews, 3)
    elif matched_any:
        # fallback average of avgs
        vals = [ref_map[ref][0] for ref in biz_refs if ref in ref_map and ref_map[ref][0] is not None]
        average_rating = round(sum(vals)/len(vals),3) if vals else None
    else:
        average_rating = None
    result = {"state": max_state, "wifi_business_count": max_count, "average_rating": average_rating}

print("__RESULT__:")
print(json.dumps(result))

